import React, { type CSSProperties, useEffect, useRef, useState } from 'react'
import { type CSSStyle } from '#repositories/types/foundation'
import { Image, type ImageProps } from 'antd'
import useFetchState from '#repositories/models'
import { Setting as SSetting } from '#repositories/models/recoil-state'
import { isImageAccessibleFetch } from '#utils/functions'

interface PropsType {
	className?: string
	src: string
	alt?: string
	style?: CSSStyle
	preview?: boolean
}

const Main: React.FC<PropsType> = props => {
	const [ className, setClassName ] = useFetchState('')
	const onError = (): void => {
		setClassName('image-err')
	}

	const src = (): string => {
		return props.src
	}

	return <div className={ 'wh100 image-box' + (className !== '' ? ' ' + className : '') }>
		<Image
			className={ props.className }
			style={ props.style ?? {} }
			src={ src() }
			alt={ props.alt }
			preview={ props.preview ?? false }
			onError={ onError }
			fallback="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mP8/wDAAwAB/luBmQAAAABJRU5ErkJggg=="
		/>
	</div>
}

export default Main

export const ImageFit: React.FC<PropsType> = props => {
	return <div
		className="image-fit"
		style={ { width: '100%', aspectRatio: '16/9', position: 'relative', overflow: 'hidden' } }
	>
		<Image
			className={ props.className }
			style={ { position: 'absolute', width: '100%', height: '100%', objectFit: 'cover' } }
			src={ props.src }
			alt={ props.alt }
			preview={ props.preview ?? false }
			fallback="data:image/png;base64,"
		/>
	</div>
}

interface AutoFitImageProps extends Omit<ImageProps, 'width' | 'height'> {
	containerClassName?: string
	proxy?: boolean
	width?: number
	height?: number
	reloadInterval?: number
	inner?: boolean // 新增参数
}

export const AutoFitImage: React.FC<AutoFitImageProps> = (
	{
		src,
		proxy,
		containerClassName = '',
		reloadInterval,
		inner = false, // 默认值为false
		...restProps
	}
) => {
	const settingState = new SSetting().shared()
	const reloadIntervalRef = useRef<any>(null)
	const srcValRef = useRef('')
	const containerRef = useRef<HTMLDivElement>(null)

	const [ srcVal, setSrcVal ] = useFetchState('')
	const [ imageLoaded, setImageLoaded ] = useState(false)
	const [ imageSize, setImageSize ] = useState({ width: 0, height: 0 })

	const loadImage = (): void => {
		clearTimeout(reloadIntervalRef.current as number)
		const src = `${ srcValRef.current.split('?')[ 0 ] }?r=${ new Date().valueOf() }`
		void isImageAccessibleFetch(src).then(
			() => {
				setSrcVal(src)
			}
		).finally(
			() => {
				reloadIntervalRef.current = setTimeout(loadImage, (reloadInterval ?? 4) * 1000)
			}
		)
	}

	const getImageSize = async(imgSrc: string): Promise<{ width: number, height: number }> => await new Promise(
		(resolve) => {
			const img = new window.Image()
			img.onload = () => {
				resolve({
					width: img.width,
					height: img.height
				})
			}
			img.onerror = () => {
				resolve({ width: 0, height: 0 })
			}
			img.src = imgSrc
		}
	)

	const getImageStyle = (): CSSProperties => {
		if (!imageLoaded || containerRef.current === null) {
			return {}
		}

		if (inner) { // 如果 inner=true，则使用 contain 模式
			return {
				width: '100%',
				height: '100%',
				objectFit: 'contain',
				objectPosition: 'center'
			}
		} else {
			const container = containerRef.current
			const containerWidth = container.offsetWidth
			const containerHeight = container.offsetHeight
			const containerRatio = containerWidth / containerHeight
			const imageRatio = imageSize.width / imageSize.height

			if (imageSize.width >= imageSize.height || imageRatio >= containerRatio) {
				// 图片宽大于等于高，或者图片宽高比大于等于容器宽高比
				// 上下撑满容器，左右超出裁剪
				return {
					width: 'auto',
					height: '100%',
					objectFit: 'cover',
					objectPosition: 'center'
				}
			} else {
				// 图片高大于宽，或者图片宽高比小于容器宽高比
				// 左右撑满容器，上下超出裁剪
				return {
					width: '100%',
					height: 'auto',
					objectFit: 'cover',
					objectPosition: 'center'
				}
			}
		}
	}

	const handleImageLoad = async(): Promise<void> => {
		if (srcVal !== '') {
			const size = await getImageSize(srcVal)
			setImageSize(size)
			setImageLoaded(true)
		}
	}

	useEffect(
		() => {
			let srcVal = src ?? ''
			if (proxy === true && srcVal !== '') {
				srcVal = `${ settingState[ 'proxy-file-url' ] }/${ srcVal.replace(/^\//, '') }`
			}

			srcValRef.current = srcVal
			setSrcVal(srcVal)
			setImageLoaded(false) // 重置加载状态
		},
		[ src ]
	)

	useEffect(
		() => {
			if (src === '' || reloadInterval === undefined) {
				return
			}

			loadImage()
			return () => {
				setTimeout(
					() => {
						clearTimeout(reloadIntervalRef.current as number)
					},
					500
				)
			}
		},
		[]
	)

	return <div ref={ containerRef } className={ `auto-fit-image-container ${ containerClassName }` }>
		<Image
			src={ srcVal }
			className="auto-fit-image"
			style={ getImageStyle() }
			onLoad={ () => { void handleImageLoad() } }
			{ ...restProps }
			data-src={ srcVal }
			fallback="data:image/png;base64,"
		/>
	</div>
}